// Get current temperature and 4-hour trend from Tomorrow.io
const config = $('Load Config').first().json;

const LAT = config.location.latitude;
const LON = config.location.longitude;
const API_KEY = config.secrets.TOMORROW_IO_KEY;

const url = `https://api.tomorrow.io/v4/weather/forecast?location=${LAT},${LON}&timesteps=1h&apikey=${API_KEY}`;

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: url,
  json: true
});

const hourly = (response.timelines?.hourly || []).slice(0, 5);
const currentTemp = hourly[0]?.values?.temperature || null;
const tempIn4h = hourly[4]?.values?.temperature || currentTemp;

// Determine trend
let trend = 'Stable';
if (tempIn4h !== null && currentTemp !== null) {
  const diff = tempIn4h - currentTemp;
  if (diff < -3) trend = `Dropping fast from ${currentTemp}C to ${tempIn4h}C`;
  else if (diff < -1) trend = `Dropping slowly from ${currentTemp}C to ${tempIn4h}C`;
  else if (diff > 3) trend = `Rising fast from ${currentTemp}C to ${tempIn4h}C`;
  else if (diff > 1) trend = `Rising slowly from ${currentTemp}C to ${tempIn4h}C`;
  else trend = `Stable around ${currentTemp}C`;
}

const now = new Date();
const month = now.getMonth() + 1;
const hour = now.getHours();
const isSummer = config.settings.SUMMER_MONTHS.includes(month);

return [{
  json: {
    currentTemp,
    tempIn4h,
    trend,
    month,
    hour,
    isSummer,
    currentTime: now.toISOString()
  }
}];

// AI Kids' Sleep & Climate Guardian
// Decides whether to turn kids AC ON or OFF based on temperature and season
const config = $('Load Config').first().json;
const weather = $input.first().json;

const GEMINI_KEY = config.secrets.GEMINI_API_KEY;
const DEVICE_ID = config.devices.AC_KIDS;

const prompt = `You are the "AI Kids' Sleep & Climate Guardian," a specialized environmental AI agent dedicated to maintaining optimal, healthy sleeping conditions for children while preventing energy waste.

Your controllable entity is:
- Kids' Room AC (ID: "${DEVICE_ID}" - You can only turn it ON or OFF via code "switch". Temperature is pre-set by parent.)

Current Context:
- Current Time: ${weather.currentTime}
- Hour: ${weather.hour}:00
- Current Outdoor Temp: ${weather.currentTemp}°C
- Temperature Trend (next 4 hours): ${weather.trend}
- Season: ${weather.isSummer ? 'Summer (months 5-10)' : 'Winter (months 11-4)'}
- Month: ${weather.month}

RULES:
1. SUMMER MODE (months 5-10, AC is set to Cool):
   - Turn ON when outdoor temp > 20°C
   - Turn OFF when outdoor temp drops below 17°C
   - Between 02:00-05:00 (deep sleep), prefer OFF if temp is borderline (17-20°C)

2. WINTER MODE (months 11-4, AC is set to Heat):
   - Turn ON when outdoor temp < 10°C
   - Turn OFF when outdoor temp rises above 10°C
   - Keep ON during 02:00-05:00 if temp is very cold (< 5°C)

3. ENERGY SAVING:
   - If temperature trend shows rapid cooling (summer) or warming (winter), anticipate and turn OFF early
   - Don't toggle ON/OFF for small fluctuations (hysteresis: use 2°C buffer)

4. CHILD SAFETY:
   - Never leave AC running in Cool mode if outdoor temp < 15°C
   - Never leave AC off in Heat mode if outdoor temp < 5°C

Output ONLY valid JSON:
{
  "analysis": "Brief reasoning about current conditions and decision",
  "action_required": true or false,
  "command": {
    "deviceId": "${DEVICE_ID}",
    "action": "ON or OFF",
    "commands": [{"code": "switch", "value": true or false}],
    "justification": "One sentence reason in Hebrew"
  }
}

If no action is needed (AC is already in correct state based on conditions), set action_required to false and command to null.`;

const payload = {
  contents: [{ role: "user", parts: [{ text: prompt }] }],
  generationConfig: {
    responseMimeType: "application/json",
    responseSchema: {
      type: "object",
      properties: {
        analysis: { type: "string" },
        action_required: { type: "boolean" },
        command: {
          type: "object",
          properties: {
            deviceId: { type: "string" },
            action: { type: "string" },
            commands: { type: "array", items: { type: "object", properties: { code: { type: "string" }, value: { type: "boolean" } } } },
            justification: { type: "string" }
          }
        }
      },
      required: ["analysis", "action_required"]
    }
  }
};

const url = "https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=" + GEMINI_KEY;

try {
  const response = await this.helpers.httpRequest({
    method: 'POST', url, body: payload, json: true,
    headers: { 'Content-Type': 'application/json' }
  });
  const text = response.candidates[0].content.parts[0].text;
  const result = JSON.parse(text.replace(/```json|```/g, '').trim());
  return [{ json: result }];
} catch (e) {
  return [{ json: { analysis: "Error: " + e.message, action_required: false, command: null } }];
}

// Execute AC command if action is required
const crypto = require('crypto');
const config = $('Load Config').first().json;
const aiResult = $input.first().json;

// Get weather data from earlier node for passthrough
const weatherData = $('Get Current Weather').first().json;

if (!aiResult.action_required || !aiResult.command) {
  return [{ json: { executed: false, action: 'NO CHANGE', reason: aiResult.analysis, outdoorTemp: weatherData.currentTemp } }];
}

const TUYA_ACCESS_ID = config.secrets.TUYA_ACCESS_ID;
const TUYA_ACCESS_SECRET = config.secrets.TUYA_ACCESS_SECRET;
const API_URL = 'https://openapi.tuyaeu.com';

// Get token
const timestamp = Date.now().toString();
const tokenPath = '/v1.0/token?grant_type=1';
const contentHash = crypto.createHash('sha256').update('').digest('hex');
const stringToSign = 'GET\n' + contentHash + '\n\n' + tokenPath;
const str = TUYA_ACCESS_ID + timestamp + stringToSign;
const sign = crypto.createHmac('sha256', TUYA_ACCESS_SECRET).update(str).digest('hex').toUpperCase();

const tokenResp = await this.helpers.httpRequest({
  method: 'GET',
  url: API_URL + tokenPath,
  headers: { 't': timestamp, 'sign': sign, 'client_id': TUYA_ACCESS_ID, 'sign_method': 'HMAC-SHA256' },
  json: true
});
const token = tokenResp.result.access_token;

// Send command
const cmd = aiResult.command;
const cmdTimestamp = Date.now().toString();
const cmdPath = '/v1.0/devices/' + cmd.deviceId + '/commands';
const body = JSON.stringify({ commands: cmd.commands });

const cmdContentHash = crypto.createHash('sha256').update(body).digest('hex');
const cmdStringToSign = 'POST\n' + cmdContentHash + '\n\n' + cmdPath;
const cmdStr = TUYA_ACCESS_ID + token + cmdTimestamp + cmdStringToSign;
const cmdSign = crypto.createHmac('sha256', TUYA_ACCESS_SECRET).update(cmdStr).digest('hex').toUpperCase();

const result = await this.helpers.httpRequest({
  method: 'POST',
  url: API_URL + cmdPath,
  headers: {
    't': cmdTimestamp, 'sign': cmdSign, 'client_id': TUYA_ACCESS_ID,
    'sign_method': 'HMAC-SHA256', 'access_token': token,
    'Content-Type': 'application/json'
  },
  body: body,
  json: true
});

return [{
  json: {
    executed: true,
    action: cmd.action || (cmd.commands[0].value ? 'ON' : 'OFF'),
    success: result.success,
    reason: (cmd.justification || '').substring(0, 200),
    outdoorTemp: weatherData.currentTemp
  }
}];

// Morning summary email for kids AC
